      <thead class="bg-gray-100 font-semibold">
        <tr>
          <th class="border border-gray-300 px-4 py-2">Business Need</th>
          <th class="border border-gray-300 px-4 py-2">How AI Agents Help</th>
        </tr>
      </thead>
      <tbody>
        <tr>
          <td class="border border-gray-300 px-4 py-2">Faster customer response</td>
          <td class="border border-gray-300 px-4 py-2">AI agents handle calls instantly, improving customer experience.</td>
        </tr>
        <tr>
          <td class="border border-gray-300 px-4 py-2">Consistent sales efforts</td>
